<template><div class="panel"><div class="section-head"><div><h2>{{ t('models.title') }}</h2><p>{{ t('models.description') }}</p></div><el-button v-if="auth.hasPermission('model:model:create')" type="primary" @click="open()">{{ t('models.add') }}</el-button></div><el-table :data="rows"><el-table-column prop="code" :label="t('common.code')"/><el-table-column prop="name" :label="t('common.name')"/><el-table-column :label="t('models.provider')"><template #default="s">{{providerName(s.row.providerId)}}</template></el-table-column><el-table-column prop="modelName" :label="t('models.identifier')"/><el-table-column prop="modelType" :label="t('models.modelType')"/><el-table-column prop="capabilityLevel" :label="t('models.capability')"/><el-table-column :label="t('common.operation')"><template #default="s"><el-button link type="success" @click="test(s.row)">{{ t('models.test') }}</el-button><el-button link type="primary" @click="open(s.row)">{{ t('common.edit') }}</el-button><el-button link type="danger" @click="remove(s.row)">{{ t('common.delete') }}</el-button></template></el-table-column></el-table><el-dialog v-model="visible" :title="form.id?t('models.edit'):t('models.add')"><el-form label-width="100px"><el-form-item :label="t('common.code')"><el-input v-model="form.code"/></el-form-item><el-form-item :label="t('common.name')"><el-input v-model="form.name"/></el-form-item><el-form-item :label="t('models.provider')"><el-select v-model="form.providerId"><el-option v-for="item in providers" :key="item.id" :label="item.name" :value="item.id"/></el-select></el-form-item><el-form-item :label="t('models.identifier')"><el-input v-model="form.modelName"/></el-form-item><el-form-item :label="t('models.modelType')"><el-select v-model="form.modelType"><el-option :label="t('models.text')" value="TEXT"/><el-option :label="t('models.vision')" value="VISION"/></el-select></el-form-item><el-form-item :label="t('models.capability')"><el-select v-model="form.capabilityLevel"><el-option :label="t('models.low')" value="LOW"/><el-option :label="t('models.middle')" value="MIDDLE"/><el-option :label="t('models.high')" value="HIGH"/></el-select></el-form-item><el-form-item :label="t('common.enabled')"><el-switch v-model="form.enabled"/></el-form-item></el-form><template #footer><el-button @click="visible=false">{{ t('common.cancel') }}</el-button><el-button type="primary" @click="save">{{ t('common.save') }}</el-button></template></el-dialog></div></template>
<script setup>import{onMounted,reactive,ref}from'vue';import{ElMessage,ElMessageBox}from'element-plus';import{useI18n}from'vue-i18n';import http from'../api/http';import{useAuthStore}from'../stores/auth';const{t}=useI18n();const auth=useAuthStore(),rows=ref([]),providers=ref([]),visible=ref(false),form=reactive({id:null,code:'',name:'',providerId:null,modelName:'',modelType:'TEXT',capabilityLevel:'MIDDLE',enabled:true});async function load(){[rows.value,providers.value]=await Promise.all([http.get('/models').then(r=>r.data),http.get('/models/providers').then(r=>r.data)])}/** 打开模型窗口。 */function open(row){Object.assign(form,row?{...row}:{id:null,code:'',name:'',providerId:null,modelName:'',modelType:'TEXT',capabilityLevel:'MIDDLE',enabled:true});visible.value=true}/** 保存模型。 */async function save(){form.id?await http.put(`/models/${form.id}`,form):await http.post('/models',form);visible.value=false;await load();ElMessage.success(t('common.successSaved'))}/** 测试模型连接。 */async function test(row){const result=(await http.post(`/models/${row.id}/test`)).data;ElMessage.success(t('models.connected',{duration:result.durationMs}))}/** 删除模型。 */async function remove(row){await ElMessageBox.confirm(t('common.confirmDelete',{name:row.name}),t('common.deleteConfirm'),{type:'warning'});await http.delete(`/models/${row.id}`);await load();ElMessage.success(t('common.successDeleted'))}function providerName(id){return providers.value.find(item=>item.id===id)?.name||id}onMounted(load)</script>
